args.sparql:
SELECT ?author ?authorLabel ?workLabel WHERE {
  # Bind museum and award entities
  BIND(wd:Q1967496 AS ?museum)
  BIND(wd:Q7243277 AS ?award)

  # Works winning the award in 2012
  ?work p:P166 [ 
    ps:P166 ?award ;
    pq:P585 ?awardDate 
  ]. 
  FILTER(YEAR(?awardDate) = 2012)
  ?work wdt:P50 ?author .

  # Find deputy chair positions (direct property path)
  ?author wdt:P39 ?position .
  ?position wdt:P463 ?museum ;
          rdfs:label ?positionLabel .
  FILTER(CONTAINS(LCASE(?positionLabel), "deputy chair"))

  # Get English labels
  OPTIONAL { ?author rdfs:label ?authorLabel . FILTER(LANG(?authorLabel) = 'en') }
  OPTIONAL { ?work rdfs:label ?workLabel . FILTER(LANG(?workLabel) = 'en') }
}
LIMIT 10
